<router-link custom v-slot="{ href, navigate, isActive, isExactActive }" :to="props.path"><li class="item" :class="[isActive &amp;&amp; 'router-link-active', isExactActive &amp;&amp; 'router-link-exact-active']"><a class="link" :href="href" @click="[navigate($event), closeNavigation()]">{{ routeName }}</a></li></router-link>